namespace sv_3e27431e4d294d89b67f218b9b03f549.Client.Models;

public sealed record Shipment(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> StatusUpdates);

public sealed record StatusUpdate(
    string Description,
    string Location,
    DateTimeOffset Timestamp);

using sv_3e27431e4d294d89b67f218b9b03f549.Client.Models;

namespace sv_3e27431e4d294d89b67f218b9b03f549.Client.Services;

public interface IShipmentService
{
    Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_3e27431e4d294d89b67f218b9b03f549.Client.Models;
using sv_3e27431e4d294d89b67f218b9b03f549.Client.Services;

namespace sv_3e27431e4d294d89b67f218b9b03f549.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment(
            TrackingNumber: "PKG-001",
            Status: "In Transit",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 25, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new("Package picked up", "New York, NY", new DateTimeOffset(2026, 5, 20, 9, 0, 0, TimeSpan.Zero)),
                new("Departed facility", "New York, NY", new DateTimeOffset(2026, 5, 20, 14, 30, 0, TimeSpan.Zero)),
                new("Arrived at sort facility", "Chicago, IL", new DateTimeOffset(2026, 5, 21, 6, 15, 0, TimeSpan.Zero)),
                new("In transit to destination", "Chicago, IL", new DateTimeOffset(2026, 5, 22, 8, 0, 0, TimeSpan.Zero)),
            }),

        ["PKG-002"] = new Shipment(
            TrackingNumber: "PKG-002",
            Status: "Delivered",
            Location: "San Francisco, CA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 21, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new("Package picked up", "Seattle, WA", new DateTimeOffset(2026, 5, 18, 10, 0, 0, TimeSpan.Zero)),
                new("Departed facility", "Seattle, WA", new DateTimeOffset(2026, 5, 18, 16, 0, 0, TimeSpan.Zero)),
                new("Arrived at destination facility", "San Francisco, CA", new DateTimeOffset(2026, 5, 20, 7, 0, 0, TimeSpan.Zero)),
                new("Out for delivery", "San Francisco, CA", new DateTimeOffset(2026, 5, 21, 8, 30, 0, TimeSpan.Zero)),
                new("Delivered", "San Francisco, CA", new DateTimeOffset(2026, 5, 21, 11, 45, 0, TimeSpan.Zero)),
            }),

        ["PKG-003"] = new Shipment(
            TrackingNumber: "PKG-003",
            Status: "Processing",
            Location: "Dallas, TX",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 28, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new("Label created", "Dallas, TX", new DateTimeOffset(2026, 5, 22, 14, 0, 0, TimeSpan.Zero)),
            }),
    };

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"No shipment found for tracking number '{trackingNumber}'.");
    }
}

@page "/shipments/{TrackingNumber}"
@using sv_3e27431e4d294d89b67f218b9b03f549.Client.Models
@using sv_3e27431e4d294d89b67f218b9b03f549.Client.Services
@rendermode InteractiveAuto
@implements IDisposable
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <h2>Shipment @_shipment.TrackingNumber</h2>
    <dl>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>
        <dt>Location</dt>
        <dd>@_shipment.Location</dd>
        <dt>Estimated Delivery</dt>
        <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h3>Status Updates</h3>
    <table>
        <thead>
            <tr>
                <th>Time</th>
                <th>Location</th>
                <th>Description</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var update in _shipment.StatusUpdates)
            {
                <tr>
                    <td>@update.Timestamp.ToString("g")</td>
                    <td>@update.Location</td>
                    <td>@update.Description</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _shipment = null;
        _errorMessage = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed; do nothing.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex) when (ex is not OperationCanceledException)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryLoad()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

